import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Wallet, TrendingDown, ArrowRight, ShoppingBag } from 'lucide-react';
import { Link } from 'react-router-dom';

const Menu = () => {
  const [resumo, setResumo] = useState({ total: 0, quantidade: 0 });

  useEffect(() => {
    async function buscarResumo() {
      const { data, error } = await supabase
        .from('compras')
        .select('valor_total');
      
      if (data) {
        const soma = data.reduce((acc, item) => acc + parseFloat(item.valor_total), 0);
        setResumo({ total: soma, quantidade: data.length });
      }
    }
    buscarResumo();
  }, []);

  return (
    <div className="fade-in">
      <header style={{ marginBottom: '40px' }}>
        <h1 style={{ fontSize: '2rem', margin: 0 }}>Dashboard Inicial</h1>
        <p style={{ color: 'var(--text-muted)' }}>Resumo atualizado das suas finanças.</p>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' }}>
        
        {/* Card de Valor Total */}
        <div className="card" style={{ borderLeft: '5px solid var(--primary)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: 'var(--text-muted)', fontWeight: '600' }}>Gasto Acumulado</span>
            <Wallet size={20} color="var(--primary)" />
          </div>
          <h2 style={{ fontSize: '1.8rem', margin: '15px 0 5px 0' }}>
            R$ {resumo.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
          </h2>
          <small style={{ color: 'var(--text-muted)' }}>Total de todas as compras</small>
        </div>

        {/* Card de Quantidade */}
        <div className="card" style={{ borderLeft: '5px solid var(--success)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ color: 'var(--text-muted)', fontWeight: '600' }}>Lançamentos</span>
            <ShoppingBag size={20} color="var(--success)" />
          </div>
          <h2 style={{ fontSize: '1.8rem', margin: '15px 0 5px 0' }}>{resumo.quantidade}</h2>
          <small style={{ color: 'var(--text-muted)' }}>Itens registrados no banco</small>
        </div>

        {/* Card de Atalho */}
        <div className="card" style={{ background: 'var(--primary)', color: 'white' }}>
          <h3 style={{ margin: 0 }}>Novo Gasto?</h3>
          <p style={{ opacity: 0.9, fontSize: '0.9rem' }}>Registre notas e pedidos agora.</p>
          <Link to="/lancamento" className="btn-primary" style={{ background: 'white', color: 'var(--primary)', display: 'inline-flex', alignItems: 'center', gap: '8px', textDecoration: 'none', marginTop: '10px', fontSize: '0.9rem' }}>
            Lançar Agora <ArrowRight size={16} />
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Menu;
